'use strict';

const vscode = require('vscode');
const { execFile } = require('child_process');
const path = require('path');

function getWorkspaceRoot() {
	const folder = vscode.workspace.workspaceFolders?.[0];
	return folder?.uri.fsPath;
}

function runGoto() {
	const editor = vscode.window.activeTextEditor;
	if (!editor) {
		return;
	}
	const root = getWorkspaceRoot();
	if (!root) {
		vscode.window.showErrorMessage('AOSP Gtags: open the aosp14 workspace folder first.');
		return;
	}
	const script = path.join(root, 'tools', 'global-goto-at-cursor.sh');
	const file = editor.document.uri.fsPath;
	const pos = editor.selection.active;
	const line = String(pos.line + 1);
	const col = String(pos.character + 1);

	execFile(
		script,
		[file, line, col],
		{
			cwd: root,
			env: { ...process.env, GTAGS_GOTO_NO_OPEN: '1' },
			maxBuffer: 4 * 1024 * 1024,
		},
		(err, stdout, stderr) => {
			if (err) {
				const msg = (stderr || err.message || String(err)).trim();
				vscode.window.showErrorMessage(
					msg || `Gtags: no definition (run ./tools/gtags-index.sh all)`
				);
				return;
			}
			const out = stdout.trim().split('\n').pop() || '';
			const m = out.match(/^(.+):(\d+)$/);
			if (!m) {
				vscode.window.showErrorMessage(`Gtags: unexpected output: ${out}`);
				return;
			}
			const target = vscode.Uri.file(m[1]);
			const line0 = Math.max(0, parseInt(m[2], 10) - 1);
			vscode.window.showTextDocument(target, {
				selection: new vscode.Range(line0, 0, line0, 0),
				preserveFocus: false,
			});
		}
	);
}

/** @param {vscode.ExtensionContext} context */
function activate(context) {
	context.subscriptions.push(
		vscode.commands.registerCommand('aospGtags.gotoDefinition', runGoto)
	);
}

function deactivate() {}

module.exports = { activate, deactivate };

