'use strict';

const vscode = require('vscode');
const { execFileSync } = require('child_process');
const path = require('path');

const LANGS = ['c', 'cpp', 'java'];

function getWorkspaceRoot() {
	return vscode.workspace.workspaceFolders?.[0]?.uri.fsPath;
}

function symbolAtCursor(document, position) {
	const script = path.join(getWorkspaceRoot() || '', 'tools', 'global-locations-at-cursor.sh');
	// Reuse lookup scripts: they read symbol from file/line/col internally.
	return { file: document.uri.fsPath, line: position.line + 1, col: position.character + 1 };
}

function runLookup(scriptName, document, position) {
	const root = getWorkspaceRoot();
	if (!root) {
		return [];
	}
	const script = path.join(root, 'tools', scriptName);
	const { file, line, col } = symbolAtCursor(document, position);
	try {
		const stdout = execFileSync(script, [file, String(line), String(col)], {
			cwd: root,
			encoding: 'utf8',
			maxBuffer: 8 * 1024 * 1024,
		});
		const locations = [];
		for (const raw of stdout.trim().split('\n')) {
			const m = raw.trim().match(/^(.+):(\d+)$/);
			if (!m) {
				continue;
			}
			const line0 = Math.max(0, parseInt(m[2], 10) - 1);
			locations.push(
				new vscode.Location(vscode.Uri.file(m[1]), new vscode.Position(line0, 0))
			);
		}
		return locations;
	} catch {
		return [];
	}
}

class GtagsDefinitionProvider {
	provideDefinition(document, position) {
		const locs = runLookup('global-locations-at-cursor.sh', document, position);
		if (locs.length === 0) {
			return null;
		}
		return locs.length === 1 ? locs[0] : locs;
	}
}

class GtagsReferenceProvider {
	provideReferences(document, position, _context, _token) {
		return runLookup('global-references-at-cursor.sh', document, position);
	}
}

function runGoto() {
	vscode.commands.executeCommand('editor.action.revealDefinition');
}

function runFindReferences() {
	vscode.commands.executeCommand('editor.action.goToReferences');
}

function runGoBack() {
	vscode.commands.executeCommand('workbench.action.navigateBack');
}

function runGoForward() {
	vscode.commands.executeCommand('workbench.action.navigateForward');
}

/** @param {vscode.ExtensionContext} context */
function activate(context) {
	const defProvider = new GtagsDefinitionProvider();
	const refProvider = new GtagsReferenceProvider();
	for (const lang of LANGS) {
		context.subscriptions.push(
			vscode.languages.registerDefinitionProvider(lang, defProvider),
			vscode.languages.registerReferenceProvider(lang, refProvider)
		);
	}
	context.subscriptions.push(
		vscode.commands.registerCommand('aospGtags.gotoDefinition', runGoto),
		vscode.commands.registerCommand('aospGtags.findReferences', runFindReferences),
		vscode.commands.registerCommand('aospGtags.goBack', runGoBack),
		vscode.commands.registerCommand('aospGtags.goForward', runGoForward)
	);
}

function deactivate() {}

module.exports = { activate, deactivate };

